Below is a Python example illustrating a simplified compliance check for CEO/CFO sign-off on financial statements:

python
class FinancialStatement:
    def __init__(self, ceo_signed=False, cfo_signed=False, submitted_to_board=False):
        self.ceo_signed = ceo_signed
        self.cfo_signed = cfo_signed
        self.submitted_to_board = submitted_to_board

    def check_clerp9_compliance(self):
        if not (self.ceo_signed and self.cfo_signed):
            return "Non-compliant: CEO and/or CFO sign-off missing"
        elif not self.submitted_to_board:
            return "Non-compliant: Statement not submitted to board"
        else:
            return "Compliant: CEO and CFO sign-off verified, submitted to board"

# Example usage
fs = FinancialStatement(ceo_signed=True, cfo_signed=True, submitted_to_board=True)
print(fs.check_clerp9_compliance())  # Output: Compliant: CEO and CFO sign-off verified, submitted to board
